from flask import Flask, request, jsonify
from flask import g
import jwt
import requests
from functools import wraps

app = Flask(__name__)
app.config['SECRET_KEY'] = 'your-secret-key-here'

def token_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        
        if not auth_header or not auth_header.startswith('Bearer '):
            return jsonify({'error': 'Missing or invalid Authorization header'}), 401
        
        token = auth_header.split(' ')[1]
        
        try:
            # For development only - in production use proper verification
            decoded_token = jwt.decode(token, app.config['SECRET_KEY'], algorithms=['HS256'], options={"verify_signature": False})
            g.user_claims = decoded_token
        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token has expired'}), 401
        except jwt.InvalidTokenError:
            return jsonify({'error': 'Invalid token'}), 401
            
        return f(*args, **kwargs)
    return decorated

@app.before_request
def before_request():
    # Add any pre-request logic here
    pass

@app.route('/api/<path:service_path>', methods=['GET', 'POST', 'PUT', 'DELETE'])
@token_required
def forward_request(service_path):
    try:
        # Forward request to backend service
        backend_url = f"http://backend-service:8000/{service_path}"
        
        # Prepare headers for backend service
        headers = {}
        for key, value in request.headers:
            if key.lower() not in ['authorization', 'host']:
                headers[key] = value
        
        # Add user claims to headers
        headers['X-User-Claims'] = str(g.user_claims)
        
        # Forward the request
        response = requests.request(
            method=request.method,
            url=backend_url,
            headers=headers,
            data=request.get_data(),
            params=request.args,
            timeout=30
        )
        
        return response.content, response.status_code, response.headers.items()
        
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Backend service error'}), 502

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=False)